Rules.InvariantScript:
Patch(CRRequests,
  If(gblCRMode = "New", Defaults(CRRequests), gblDetailCR),
  {
    Title: Upper(txtProgCodeSCS.Text) & ": " & txtCRNumSCS.Text & " - " & Upper(txtTitleSCS.Text),
    CRNumber: txtCRNumSCS.Text,
    ProgrammeCode: Upper(txtProgCodeSCS.Text),
    ProgrammeName: txtProgNameSCS.Text,
    CRTitle: Upper(txtTitleSCS.Text),
    Supplier: txtSupplierSCS.Text,
    SupplierReference: txtSupRefSCS.Text,
    AIPSGTargetDate: dteAIPSGSCS.SelectedDate,
    SubmissionDeadline: dteDeadlineSCS.SelectedDate,
    IsDraft: true,
    CRStatus: {Value: "Draft"},
    Originator: {Claims: "i:0#.f|membership|" & User().Email, DisplayName: User().FullName, Department: ""}
  }
);
If(IsEmpty(Errors(CRRequests)),
  Navigate('View CRs Screen', ScreenTransition.None);
  Notify("Draft saved.", NotificationType.Success),
  Notify("Save failed — " & First(Errors(CRRequests)).Message, NotificationType.Error)
)

If(
  IsBlank(txtCRNumSCS.Text) Or IsBlank(txtProgCodeSCS.Text) Or IsBlank(txtProgNameSCS.Text) Or IsBlank(txtTitleSCS.Text) Or IsBlank(cmbPMSCS.Selected.Email) Or IsBlank(cmbSponsorSCS.Selected.Email) Or IsBlank(dteAIPSGSCS.SelectedDate),
  Set(gblFormError, "Please complete all required fields (*) before continuing"),
  Set(gblFormError, "");
  Set(gblDetailCR,
    Patch(CRRequests,
      If(gblCRMode = "New", Defaults(CRRequests), gblDetailCR),
      {
        Title: Upper(txtProgCodeSCS.Text) & ": " & txtCRNumSCS.Text & " - " & Upper(txtTitleSCS.Text),
        CRNumber: txtCRNumSCS.Text,
        ProgrammeCode: Upper(txtProgCodeSCS.Text),
        ProgrammeName: txtProgNameSCS.Text,
        CRTitle: Upper(txtTitleSCS.Text),
        Supplier: txtSupplierSCS.Text,
        SupplierReference: txtSupRefSCS.Text,
        ProjectManager: {Claims: "i:0#.f|membership|" & cmbPMSCS.Selected.Email, DisplayName: cmbPMSCS.Selected.Title, Department: ""},
        CRSponsor: {Claims: "i:0#.f|membership|" & cmbSponsorSCS.Selected.Email, DisplayName: cmbSponsorSCS.Selected.Title, Department: ""},
        AIPSGTargetDate: dteAIPSGSCS.SelectedDate,
        SubmissionDeadline: dteDeadlineSCS.SelectedDate,
        IsDraft: true,
        CRStatus: {Value: "Draft"},
        Originator: {Claims: "i:0#.f|membership|" & User().Email, DisplayName: User().FullName, Department: ""}
      }
    )
  );
  If(IsEmpty(Errors(CRRequests)),
    Set(gblCRMode, "Edit");
    Navigate('Submit CR B Screen', ScreenTransition.None),
    Set(gblFormError, "Save failed — " & First(Errors(CRRequests)).Message)
  )
)
